import { useState, useEffect, useRef } from 'react'
import { Play, Pause, Volume2, VolumeX, Clock, Loader, ExternalLink, Archive } from 'lucide-react'
import { useNowPlaying } from '../../hooks/useNowPlaying'
import { useAudioPlayer } from '../../hooks/useAudioPlayer'
import styles from './PublicPlayer.module.css'

const RADIO_LOGO = '/square.gif'
const LOGO_PLATEFORME = 'data:image/png;base64,'
const LOGO_IF = 'data:image/png;base64,'

// Canvas vagues de fond pleine page
const WaveCanvas = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null)

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    let phaseH = 0
    let phaseV = 0
    let animId: number

    const resize = () => {
      canvas.width = window.innerWidth
      canvas.height = window.innerHeight
    }
    window.addEventListener('resize', resize)
    resize()

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height)
      ctx.strokeStyle = '#ffffff'
      ctx.lineWidth = 2.5

      const spacing = 60
      const amplitude = 26
      const wavelength = 320
      const numWaves = Math.ceil(canvas.height / spacing) + 2

      for (let i = 0; i < numWaves; i++) {
        const baseY = i * spacing + Math.sin(phaseV * 0.03 + i * 0.5) * 8
        ctx.beginPath()
        for (let x = 0; x <= canvas.width; x += 2) {
          const y = baseY + Math.sin((x / wavelength) * Math.PI * 2 + (i * 0.7) - phaseH) * amplitude
          if (x === 0) ctx.moveTo(x, y)
          else ctx.lineTo(x, y)
        }
        ctx.stroke()
      }
      phaseH += 0.018
      phaseV += 0.6
      animId = requestAnimationFrame(draw)
    }
    draw()

    return () => {
      window.removeEventListener('resize', resize)
      cancelAnimationFrame(animId)
    }
  }, [])

  return (
    <canvas
      ref={canvasRef}
      className={styles.waveBg}
      style={{ opacity: 0.13 }}
    />
  )
}

// Animation barres audio
const WaveAnimation = ({ active }: { active: boolean }) => (
  <div className={`${styles.wave} ${active ? styles.waveActive : ''}`}>
    {[1, 2, 3, 4, 5].map((i) => (
      <span
        key={i}
        style={{
          height: `${8 + i * 3}px`,
          animationDelay: `${i * 0.12}s`,
        }}
      />
    ))}
  </div>
)

const formatTime = (timestamp: number) => {
  const date = new Date(timestamp * 1000)
  return date.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' })
}

export default function PublicPlayer() {
  const { data, loading, error } = useNowPlaying(5000)
  const { isPlaying, isLoading, volume, isMuted, togglePlay, setVolume, toggleMute } =
    useAudioPlayer()
  const [showHistory, setShowHistory] = useState(false)

  const isLive = data?.live?.is_live ?? false
  const streamerName = data?.live?.streamer_name ?? ''
  const history = data?.song_history ?? []
  const song = data?.now_playing?.song

  return (
    <div className={styles.container}>
      <WaveCanvas />

      {/* Boutons coins — desktop uniquement */}
      <a
        href="https://thomaslefevre-plateforme.github.io/Radio-EPHEM7RE/"
        target="_blank"
        rel="noopener noreferrer"
        className={styles.cornerBtnLeft}
      >
        <ExternalLink size={14} />
        Participez à notre radio
      </a>

      <button
        className={styles.cornerBtnRight}
        onClick={() => {/* TODO: Archive */}}
      >
        <Archive size={14} />
        Archive
      </button>

      {/* Logos desktop — coins bas */}
      <div className={styles.desktopLogoLeft}>
        <img src={LOGO_PLATEFORME} alt="La Plateforme" className={styles.desktopLogoImg} />
      </div>
      <div className={styles.desktopLogoRight}>
        <img src={LOGO_IF} alt="Institut Français" className={styles.desktopLogoImg} />
      </div>

      <div className={styles.content}>

        {/* Header — live badge uniquement si en direct */}
        <header className={styles.header}>
          {isLive && (
            <div className={styles.liveBadge}>
              <span className={styles.liveDot} />
              En direct
            </div>
          )}
        </header>

        {/* Boutons mobile — cachés sur desktop */}
        <div className={styles.mobileBtns}>
          <a
            href="https://thomaslefevre-plateforme.github.io/Radio-EPHEM7RE/"
            target="_blank"
            rel="noopener noreferrer"
            className={styles.mobileBtn}
          >
            <ExternalLink size={13} />
            Participez
          </a>
          <button
            className={styles.mobileBtn}
            onClick={() => {/* TODO: Archive */}}
          >
            <Archive size={13} />
            Archive
          </button>
        </div>

        {/* Séparateur */}
        <div className={styles.sectionLabel}>À l'antenne</div>

        {/* Player card */}
        <main className={styles.playerCard}>

          {/* Pochette */}
          <div className={styles.artContainer}>
            <div className={styles.artPlaceholder}>
              <img
                src={RADIO_LOGO}
                alt="Radio EPHEM7RE"
                className={styles.radioLogoArt}
              />
            </div>
            <WaveAnimation active={isPlaying} />
          </div>

          {/* Infos titre */}
          <div className={styles.songInfo}>
            {loading ? (
              <>
                <div className={styles.shimmer} style={{ width: '65%', height: '26px', marginBottom: '10px' }} />
                <div className={styles.shimmer} style={{ width: '42%', height: '18px' }} />
              </>
            ) : error ? (
              <div className={styles.errorInfo}>Radio temporairement indisponible</div>
            ) : isLive ? (
              <>
                <h1 className={styles.songTitle}>{streamerName || 'DJ Live'}</h1>
                <p className={styles.songArtist}>Émission en direct</p>
              </>
            ) : (
              <>
                <h1 className={styles.songTitle}>
                  {song?.title || 'Radio EPHEM7RE'}
                </h1>
                <p className={styles.songArtist}>
                  {song?.artist || 'En diffusion'}
                </p>
              </>
            )}
          </div>

          {/* Bouton play */}
          <button
            className={styles.playBtn}
            onClick={togglePlay}
            disabled={!!error}
            aria-label={isPlaying ? 'Pause' : 'Écouter'}
          >
            {isLoading ? (
              <Loader size={28} className={styles.spinner} />
            ) : isPlaying ? (
              <Pause size={28} />
            ) : (
              <Play size={28} />
            )}
          </button>

          {/* Volume */}
          <div className={styles.volumeControl}>
            <button className={styles.iconBtn} onClick={toggleMute} aria-label="Mute">
              {isMuted || volume === 0
                ? <VolumeX size={18} />
                : <Volume2 size={18} />
              }
            </button>
            <input
              type="range"
              min={0}
              max={1}
              step={0.01}
              value={isMuted ? 0 : volume}
              onChange={(e) => setVolume(Number(e.target.value))}
              className={styles.volumeSlider}
              aria-label="Volume"
            />
          </div>
        </main>

        {/* Historique toggle */}
        {history.length > 0 && (
          <button
            className={styles.historyToggle}
            onClick={() => setShowHistory(!showHistory)}
          >
            <Clock size={14} />
            {showHistory ? "Masquer l'historique" : 'Historique des titres'}
          </button>
        )}

        {/* Historique */}
        {showHistory && history.length > 0 && (
          <div className={styles.history}>
            {history.slice(0, 8).map((item, i) => (
              <div key={i} className={styles.historyItem}>
                {item.song.art
                  ? <img src={item.song.art} alt="" className={styles.historyArt} />
                  : <img src={RADIO_LOGO} alt="" className={styles.historyArt} />
                }
                <div className={styles.historyInfo}>
                  <span className={styles.historyTitle}>{item.song.title}</span>
                  <span className={styles.historyArtist}>{item.song.artist}</span>
                </div>
                <span className={styles.historyTime}>{formatTime(item.played_at)}</span>
              </div>
            ))}
          </div>
        )}

        {/* Footer mobile uniquement */}
        <footer className={styles.footer}>
          <img src={LOGO_PLATEFORME} alt="La Plateforme" className={styles.footerLogoImg} />
          <span className={styles.footerSep}>·</span>
          <img src={LOGO_IF} alt="Institut Français" className={styles.footerLogoImg} />
        </footer>

      </div>
    </div>
  )
}